const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryKeys = Object.keys(item.binary || {});

  // Check if originated from Drive (has fileId) vs Gmail (has attachment)
  item.json.origin = item.json.id && !item.json.messageId ? 'drive' : 'gmail';
  item.json.drive_file_id = item.json.id || null;

  if (binaryKeys.length === 0) {
    item.json.fileType = 'unknown';
    item.json.has_attachment = false;
    continue;
  }
  item.json.has_attachment = true;

  const attachmentKey = binaryKeys.find(k => {
    const mime = (item.binary[k].mimeType || '').toLowerCase();
    const name = (item.binary[k].fileName || '').toLowerCase();
    return mime.includes('pdf') || mime.includes('jpeg') || mime.includes('jpg') || mime.includes('png') ||
           name.endsWith('.pdf') || name.endsWith('.jpg') || name.endsWith('.jpeg') || name.endsWith('.png');
  }) || binaryKeys[0];

  item.json.attachment_key = attachmentKey;
  item.json.pdf_filename = item.binary[attachmentKey].fileName;
  item.json.pdf_mime_type = item.binary[attachmentKey].mimeType;

  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, attachmentKey);
    if (buffer && buffer.length >= 4) {
      const magic = buffer.readUInt32BE(0);
      if (magic === 0x25504446) {
        item.json.fileType = 'pdf';
      } else if (magic === 0x89504E47) {
        item.json.fileType = 'png';
      } else if ((magic >> 8) === 0xFFD8FF || magic === 0xFFD8FFE0 || magic === 0xFFD8FFE1) {
        item.json.fileType = 'jpeg';
      } else {
        const mime = (item.binary[attachmentKey].mimeType || '').toLowerCase();
        if (mime.includes('pdf')) {
          item.json.fileType = 'pdf';
        } else if (mime.includes('jpeg') || mime.includes('jpg')) {
          item.json.fileType = 'jpeg';
        } else if (mime.includes('png')) {
          item.json.fileType = 'png';
        } else {
          item.json.fileType = 'unknown';
        }
      }
    } else {
      item.json.fileType = 'unknown';
    }
  } catch (e) {
    item.json.fileType = 'unknown';
    item.json.detection_error = e.message;
  }

  let email = null;
  if (item.json.from) {
    if (typeof item.json.from === 'string') {
      const match = item.json.from.match(/<([^>]+)>/);
      email = match ? match[1] : item.json.from;
    } else if (item.json.from.value && item.json.from.value[0]) {
      email = item.json.from.value[0].address;
    } else if (item.json.from.text) {
      const match = item.json.from.text.match(/<([^>]+)>/);
      email = match ? match[1] : item.json.from.text;
    }
  }
  item.json.sender_email = email || 'drive-system@example.com';

  item.binary = {
    attachment: item.binary[attachmentKey]
  };
}
return items;

const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryKeys = Object.keys(item.binary || {});
  if (binaryKeys.length === 0) {
    item.json.base64String = '';
    item.json.mimeType = 'image/jpeg';
    item.json.path = 'vision';
    continue;
  }

  const imageKey = binaryKeys.find(k => {
    const mime = (item.binary[k].mimeType || '').toLowerCase();
    return mime.includes('jpeg') || mime.includes('jpg') || mime.includes('png');
  }) || binaryKeys[0];

  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, imageKey);
    if (buffer) {
      item.json.base64String = buffer.toString('base64');
      item.json.mimeType = item.binary[imageKey].mimeType || 'image/jpeg';
    } else {
      item.json.base64String = '';
      item.json.mimeType = 'image/jpeg';
    }
  } catch (err) {
    console.error('Failed to encode binary to base64', err);
    item.json.base64String = '';
    item.json.mimeType = 'image/jpeg';
  }
  item.json.path = 'vision';
}
return items;

const systemPrompt = `You are a specialized invoice data extraction engine. You will receive either raw text or an image of an invoice. Extract structured data and return ONLY valid JSON with no markdown formatting, no explanations, no preamble.

Return this exact JSON structure with all fields present:

{
  "invoice_number": {"value": null, "confidence": 0},
  "invoice_date": {"value": null, "confidence": 0},
  "due_date": {"value": null, "confidence": 0},
  "vendor": {
    "name": {"value": null, "confidence": 0},
    "address": {"value": null, "confidence": 0},
    "email": {"value": null, "confidence": 0}
  },
  "client": {
    "name": {"value": null, "confidence": 0}
  },
  "line_items": [
    {
      "description": {"value": null, "confidence": 0},
      "quantity": {"value": null, "confidence": 0},
      "unit_price": {"value": null, "confidence": 0},
      "line_total": {"value": null, "confidence": 0}
    }
  ],
  "currency": {"value": null, "confidence": 0},
  "subtotal": {"value": null, "confidence": 0},
  "tax_amount": {"value": null, "confidence": 0},
  "total": {"value": null, "confidence": 0},
  "payment_terms": {"value": null, "confidence": 0}
}

Rules:
1. All dates must be YYYY-MM-DD format
2. All monetary values must be numeric only (no $, no commas)
3. If a field is not present, use {"value": null, "confidence": 100}
4. line_items must be an array (even if single item)

Additional Rule for Images: If reading from an image, infer missing context visually (e.g., logos for vendor name, layout for line items). If a field is completely illegible, use {"value": null, "confidence": 0}.`;

const path = item.json.path || 'text';
let content = [];

if (path === 'text') {
  let extractedText = item.json.text || '';
  if (extractedText.length > 10000) {
    extractedText = extractedText.substring(0, 10000) + '\n... [TRUNCATED DUE TO 10,000 CHAR LIMIT]';
  }
  content = [
    {
      type: "text",
      text: `${systemPrompt}\n\nINVOICE TEXT:\n${extractedText}`
    }
  ];
} else if (path === 'vision') {
  const base64String = item.json.base64String || '';
  const mimeType = item.json.mimeType || 'image/jpeg';
  content = [
    {
      type: "text",
      text: systemPrompt
    },
    {
      type: "image",
      source: {
        type: "base64",
        media_type: mimeType,
        data: base64String
      }
    }
  ];
}

item.json.claude_payload = {
  model: 'claude-3-5-sonnet-20241022',
  max_tokens: 2000,
  messages: [
    {
      role: 'user',
      content: content
    }
  ]
};
return item;

let extracted = {
  invoice_number: null,
  invoice_date: null,
  due_date: null,
  vendor_name: null,
  vendor_address: null,
  vendor_email: null,
  client_name: null,
  subtotal: null,
  tax_amount: null,
  total: null,
  currency: null,
  raw_response: null
};

if (item.json.error || !item.json.content || !item.json.content[0] || !item.json.content[0].text) {
  extracted.raw_response = item.json.error ? JSON.stringify(item.json.error) : 'API_FAILED_OR_INVALID_RESPONSE';
  item.json.extracted_data = extracted;
  item.json.extracted_json = null;
  item.json.success = false;
  return item;
}

const rawText = item.json.content[0].text;
extracted.raw_response = rawText;

try {
  let jsonStr = rawText.trim();
  if (jsonStr.includes('```json')) {
    jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  } else if (jsonStr.includes('```')) {
    jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  }

  const data = JSON.parse(jsonStr);

  extracted.invoice_number = data.invoice_number?.value ?? null;
  extracted.invoice_date = data.invoice_date?.value ?? null;
  extracted.due_date = data.due_date?.value ?? null;
  extracted.vendor_name = data.vendor?.name?.value ?? null;
  extracted.vendor_address = data.vendor?.address?.value ?? null;
  extracted.vendor_email = data.vendor?.email?.value ?? null;
  extracted.client_name = data.client?.name?.value ?? null;
  extracted.subtotal = data.subtotal?.value ?? null;
  extracted.tax_amount = data.tax_amount?.value ?? null;
  extracted.total = data.total?.value ?? null;
  extracted.currency = data.currency?.value ?? null;

  item.json.extracted_data = extracted;
  item.json.extracted_json = data;
  item.json.success = true;
} catch (err) {
  console.error('Failed to parse Claude response JSON', err);
  extracted.raw_response = 'PARSE_FAILED: ' + rawText;
  item.json.extracted_data = extracted;
  item.json.extracted_json = null;
  item.json.success = false;
}
return item;

const item = $input.item;
item.json.mathDiscrepancies = [];
item.json.flags = item.json.flags || [];

if (item.json.success && item.json.extracted_json) {
  const data = item.json.extracted_json;

  // Check 1: Line Items Sum vs Subtotal
  if (data.line_items && Array.isArray(data.line_items) && data.subtotal && data.subtotal.value !== null) {
    let lineItemsSum = 0;
    let hasLineItems = false;
    for (const line of data.line_items) {
      if (line.line_total && line.line_total.value !== null) {
        const val = parseFloat(line.line_total.value);
        if (!isNaN(val)) {
          lineItemsSum += val;
          hasLineItems = true;
        }
      }
    }

    if (hasLineItems) {
      const subtotalVal = parseFloat(data.subtotal.value);
      if (!isNaN(subtotalVal)) {
        const diff = Math.abs(lineItemsSum - subtotalVal);
        if (diff > 0.02) {
          item.json.mathDiscrepancies.push(`Line items sum (${lineItemsSum.toFixed(2)}) ≠ subtotal (${subtotalVal.toFixed(2)})`);
          item.json.flags.push("LINE_ITEM_SUM_MISMATCH");
        }
      }
    }
  }

  // Check 2: Grand Total Match
  if (data.subtotal && data.subtotal.value !== null && data.total && data.total.value !== null) {
    const subtotal = parseFloat(data.subtotal.value);
    const total = parseFloat(data.total.value);
    const tax = data.tax_amount && data.tax_amount.value !== null ? parseFloat(data.tax_amount.value) : 0;
    const discount = data.discount_amount && data.discount_amount.value !== null ? parseFloat(data.discount_amount.value) : 0;

    if (!isNaN(subtotal) && !isNaN(total)) {
      const expectedTotal = subtotal + tax - discount;
      const diff = Math.abs(expectedTotal - total);
      if (diff > 0.02) {
        item.json.mathDiscrepancies.push(`Calculated total (${expectedTotal.toFixed(2)}) ≠ stated total (${total.toFixed(2)})`);
        item.json.flags.push("TOTAL_MISMATCH");
      }
    }
  }
}

return item;

const item = $input.item;
item.json.flags = item.json.flags || [];

if (item.json.success && item.json.extracted_json) {
  const data = item.json.extracted_json;

  // Required fields check
  const required = {
    "invoice_number": data.invoice_number?.value,
    "invoice_date": data.invoice_date?.value,
    "total": data.total?.value,
    "vendor.name": data.vendor?.name?.value
  };

  for (const [key, val] of Object.entries(required)) {
    if (val === null || val === undefined) {
      const flagName = `MISSING_${key.toUpperCase().replace('.', '_')}`;
      item.json.flags.push(flagName);
    }
  }

  // Date format check
  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
  if (data.invoice_date?.value && !dateRegex.test(data.invoice_date.value)) {
    item.json.flags.push("INVALID_DATE_FORMAT_INVOICE_DATE");
  }
  if (data.due_date?.value && !dateRegex.test(data.due_date.value)) {
    item.json.flags.push("INVALID_DATE_FORMAT_DUE_DATE");
  }

  // Negative values check (Credit Notes)
  if (data.total?.value !== null && data.total?.value !== undefined) {
    const totalVal = parseFloat(data.total.value);
    if (!isNaN(totalVal) && totalVal < 0) {
      item.json.flags.push("CREDIT_NOTE");
    }
  }
} else {
  // Fail path / Unsupported file / Extraction failed
  item.json.flags.push("MISSING_INVOICE_NUMBER");
  item.json.flags.push("MISSING_INVOICE_DATE");
  item.json.flags.push("MISSING_TOTAL");
  item.json.flags.push("MISSING_VENDOR_NAME");
}

return item;

const item = $input.item;
item.json.lowConfidenceFields = [];
item.json.avgConfidence = 0;

if (item.json.success && item.json.extracted_json) {
  const data = item.json.extracted_json;
  const scores = [];
  const lowFields = [];

  function traverse(obj, path = "") {
    if (!obj || typeof obj !== "object") return;

    if ("value" in obj && "confidence" in obj) {
      if (obj.value !== null && obj.value !== undefined) {
        const conf = parseInt(obj.confidence, 10);
        if (!isNaN(conf)) {
          scores.push(conf);
          if (conf < 75) {
            lowFields.push({
              field: path,
              confidence: conf,
              value: obj.value
            });
          }
        }
      }
      return;
    }

    if (Array.isArray(obj)) {
      obj.forEach((val, idx) => {
        traverse(val, `${path}[${idx}]`);
      });
    } else {
      for (const [key, val] of Object.entries(obj)) {
        const nextPath = path ? `${path}.${key}` : key;
        traverse(val, nextPath);
      }
    }
  }

  traverse(data);

  if (scores.length > 0) {
    const sum = scores.reduce((a, b) => a + b, 0);
    item.json.avgConfidence = Math.round(sum / scores.length);
  } else {
    item.json.avgConfidence = 0;
  }
  item.json.lowConfidenceFields = lowFields;
} else {
  item.json.avgConfidence = 0;
  item.json.lowConfidenceFields = [];
}

return item;

const item = $input.item;

const mathDiscrepancies = item.json.mathDiscrepancies || [];
const flags = item.json.flags || [];
const avgConfidence = item.json.avgConfidence ?? 0;
const lowConfidenceFields = item.json.lowConfidenceFields || [];

let status = "AUTO_APPROVED";
let statusColor = "#34A853"; // Green

if (
  mathDiscrepancies.length > 0 ||
  flags.includes("MISSING_INVOICE_NUMBER") ||
  flags.includes("MISSING_TOTAL")
) {
  status = "REVIEW_REQUIRED";
  statusColor = "#EA4335"; // Red
} else if (
  avgConfidence < 75 ||
  lowConfidenceFields.length > 2 ||
  flags.includes("CREDIT_NOTE")
) {
  status = "REVIEW_RECOMMENDED";
  statusColor = "#FBBC04"; // Amber
}

item.json.status = status;
item.json.statusColor = statusColor;

return item;
